int smallestOdd(std::vector<int> const& x) {
    // We want the smallest odd integer, or `std::numeric_limits<int>::max()` if none.
    const int INF = std::numeric_limits<int>::max();
    int minOdd = INF;

    // Parallel reduce over the range. The lambda only keeps the smaller odd value.
    #pragma omp parallel for reduction(min:minOdd)
    for (size_t i = 0; i < x.size(); ++i) {
        int val = x[i];
        if ((val & 1) && val < minOdd) {   // odd & smaller
            minOdd = val;
        }
    }
    return minOdd;
