inline int maxDegree(const std::vector<int>& A, std::size_t N) {
    // Use OpenMP to parallelise the outer loop with reduction on the maximum value.
    int highestDegree = 0;
    #pragma omp parallel for reduction(max:highestDegree) schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
