inline double productWithInverses(const std::vector<double>& x)
{
    if (x.empty()) return 1.0;

    double result = 1.0;
    const size_t n = x.size();

    /* Perform the product in parallel using OpenMP reduction.
       Each iteration multiplies y[i] = x[i] for even indices
       and y[i] = 1.0 / x[i] for odd indices. */
#pragma omp parallel for reduction(*:result) num_threads(8)
    for (size_t i = 0; i < n; ++i)
    {
        if (i & 1)
            result *= 1.0 / x[i];   // odd index
        else
            result *= x[i];         // even index
    }

    return result;
}
