/* Compute the reverse prefix sum of the vector x into output.
   Examples:
   input: [1, 7, 4, 6, 6, 2]
   output: [2, 8, 14, 18, 25, 26]
   input: [3, 3, 7, 1, -2]
   output: [-2, -1, 6, 9, 12]
*/
inline void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output) {
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    // Compute the reverse prefix sum in a single loop.
    // This is equivalent to the original algorithm but avoids the allocation
    // and two passes performed by reverseX and inclusive_scan.
    int acc = 0;
    for (std::size_t i = 0; i < n; ++i) {
        acc += x[n - 1 - i];
        output[i] = acc;
    }
}
