 * The function is exactly equivalent to the reference implementation.
 */
inline void relu(std::vector<double> &x) {
    const std::size_t n = x.size();
    if (n == 0) return;

    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        double v = x[i];
        x[i] = (v > 0.0) ? v : 0.0;
    }
