#pragma once

#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/**
 * In the vector `x` negate the odd values and divide the even values by 2.
 * This implementation uses OpenMP to parallelise the transformation for
 * improved performance on multi‑core CPUs while preserving the exact
 * semantics of the original serial code.
 *
 * Example:
 *   input : [16, 11, 12, 14, 1, 0, 5]
 *   output: [8, -11, 6, 7, -1, 0, -5]
 */
inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();

    /* 
     * We avoid  a per‑iteration branch penalty by using a simple
     * arithmetic formula for the transformation:
     *   result = i/2  (if i even)
     *   result = -i   (if i odd)
     * For an integer `i` the expression `((i & 1) ? -i : i/2)` guarantees
     * the desired behaviour. The inner lambda is also inlined.
     */
    #pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < n; ++idx) {
        int i = x[idx];
        x[idx] = (i & 1) ? -i : (i >> 1);   // >> is equivalent to /2 for positives
    }
}
