/* For each letter in the alphabet, count the number of strings in the vector s that start with that letter.
   Assume all strings are in lower case and non‑empty. Store the output in `bins` array. */
inline void firstLetterCounts(std::vector<std::string> const& s, std::array<std::size_t, 26> &bins) {
    // clear output
    for (auto &v : bins) v = 0;

    // OpenMP parallelisation with per‑thread partial arrays to avoid race.
    const std::size_t n = s.size();
    const std::size_t threads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 26>> local_bins(threads);

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto &lb = local_bins[tid];          // per‑thread local bin structure
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            const unsigned char c = static_cast<unsigned char>(s[i][0]); // first character
            // safe because input is lowercase 'a'..'z'
            lb[c - 'a'] += 1;
        }
    }

    // reduce the partial results
    for (std::size_t t = 0; t < threads; ++t) {
        for (std::size_t j = 0; j < 26; ++j) {
            bins[j] += local_bins[t][j];
        }
    }
