// Counts the number of edges (entries equal to 1) in an NxN adjacency matrix
// stored in row-major order in vector<int> A.
int edgeCount(std::vector<int> const& A, size_t N) {
    int count = 0;

    // Parallelize over rows; each thread accumulates its own partial sum.
    #pragma omp parallel for reduction(+:count) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const int* row = A.data() + i * N;
#if defined(__INTEL_COMPILER) || defined(__ICC)
        // Intel compiler provides fast builtin popcount for 64-bit chunks
        for (size_t j = 0; j + 16 <= N; j += 16) {
            count += row[j]   + row[j+1] + row[j+2] + row[j+3]
                    + row[j+4] + row[j+5] + row[j+6] + row[j+7]
                    + row[j+8] + row[j+9] + row[j+10]+ row[j+11]
                    + row[j+12]+ row[j+13]+ row[j+14]+ row[j+15];
        }
#endif
        for (size_t j = 0; j < N; ++j) {
            count += row[j];
        }
    }
    return count;
}
