19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstddef>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A (row‑major).  The graph is assumed to be
   connected. */

inline int shortestPathLength(std::vector<int> const& A,
                              std::size_t N,
                              int source,
                              int dest) noexcept
{
    // Use a char array for visited: 1 byte per vertex is less than a bool
    std::vector<char> visited(N, 0);
    // Pre‑allocate queue buffers
    std::vector<int> qIdx(N);
    std::vector<int> qDist(N);
    std::size_t head = 0, tail = 0;

    visited[source] = 1;
    qIdx[tail] = static_cast<int>(source);
    qDist[tail] = 0;
    ++tail;

    while (head < tail) {
        const int v = qIdx[head];
        const int d = qDist[head];
        ++head;

        if (v == dest) return d;

        const int base = v * static_cast<int>(N);
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (A[base + i] && !visited[i]) {
                visited[i] = 1;
                qIdx[tail] = i;
                qDist[tail] = d + 1;
                ++tail;
            }
        }
    }

    return std::numeric_limits<int>::max();
}
