/* Return the logical XOR reduction of the vector of bools x.
   Example:
   input: [false, false, false, true]
   output: true
*/
inline bool reduceLogicalXOR(std::vector<bool> const& x) {
    const std::size_t n = x.size();
    if (n == 0) return false;

    const int    threads = omp_get_max_threads();
    std::vector<bool> partial(threads, false);

    #pragma omp parallel
    {
        const int tid   = omp_get_thread_num();
        bool      local = false;

        /* stride‑based chunking: each thread works on
           elements tid, tid+threads, tid+2*threads, ...   */
        for (std::size_t i = tid; i < n; i += threads) {
            local ^= x[i];
        }
        partial[tid] = local;
    }

    bool result = false;
    for (bool v : partial) result ^= v;
    return result;
}
