#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/**
 * Compute y = alpha * A * x + beta * y
 * where A is an MxN sparse matrix in COO format.
 *
 * @param alpha  Scalar multiplier for the matrix-vector product.
 * @param A      COO representation of the sparse matrix.  
 *               Elements may contain out-of-range indices; those are ignored.
 * @param x      Right‑hand side vector (size N).
 * @param beta   Scalar multiplier for the existing vector y.
 * @param y      Vector to be overwritten with the result (size M).
 * @param M      Number of rows in A (and y).
 * @param N      Number of columns in A (and x).
 */
inline void spmv(double alpha,
                 const std::vector<COOElement> &A,
                 const std::vector<double> &x,
                 double beta,
                 std::vector<double> &y,
                 std::size_t M,
                 std::size_t N)
{
    // Scale y by beta in parallel
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < M; ++i) {
        y[i] *= beta;
    }

    // Accumulate the sparse matrix contribution.
    // The accesses to y are independent per COO element, so we can safely
    // parallelise without a reduction.  Any out‑of‑range indices are ignored.
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < A.size(); ++k) {
        const auto &e = A[k];
        if (e.row < M && e.column < N) {
            // This operation is thread‑safe because different rows
            // of y are updated independently.
            y[e.row] += alpha * e.value * x[e.column];
        }
    }
}
