/*
 * Count the number of pixels in image with each grayscale intensity.
 * The vector `image` is a grayscale image with values 0-255.
 * Store the results in `bins`.
 */
inline void pixelCounts(const std::vector<int>& image,
                        std::array<std::size_t, 256> &bins)
{
    // Zero the output array
    std::fill(bins.begin(), bins.end(), 0);

    // Estimate number of threads we will use
    int nthreads = omp_get_max_threads();

    // Each thread will accumulate into its own local histogram
    std::vector<std::array<std::size_t, 256>> local_bins(nthreads);
    for (int t = 0; t < nthreads; ++t) {
        std::fill(local_bins[t].begin(), local_bins[t].end(), 0);
    }

    // Parallel loop over pixels, distributing work by block partitioning
#pragma omp parallel
    {
        int tid = omp_get_thread_num();

        // Use a local buffer to avoid bounds–checking
        auto &hb = local_bins[tid];

#pragma omp for schedule(static)
        for (std::size_t i = 0; i < image.size(); ++i) {
            hb[static_cast<unsigned char>(image[i])] += 1;
        }
    }

    // Reduce per‑thread histograms into the global result
    for (int t = 0; t < nthreads; ++t) {
        const auto &hb = local_bins[t];
        for (int val = 0; val < 256; ++val) {
            bins[val] += hb[val];
        }
    }
}
