#pragma once
#include <vector>
#include <stack>

inline void dfs_iterative(const std::vector<int>& A, size_t start, size_t N, std::vector<char>& visited) {
    std::stack<size_t> st;
    st.push(start);
    visited[start] = 1;

    while (!st.empty()) {
        size_t u = st.top();
        st.pop();

        const size_t rowOffset = u * N;
        for (size_t v = 0; v < N; ++v) {
            if (A[rowOffset + v] && !visited[v]) {
                visited[v] = 1;
                st.push(v);
            }
        }
    }
}

/**
 * Count the number of connected components in an undirected graph represented by an
 * NxN adjacency matrix A (row‑major). The function preserves the exact semantics
 * of the original implementation while being more efficient and avoiding
 * recursion overhead.
 */
inline int componentCount(const std::vector<int>& A, size_t N) {
    std::vector<char> visited(N, 0);
    int count = 0;

    for (size_t i = 0; i < N; ++i) {
        if (!visited[i]) {
            ++count;
            dfs_iterative(A, i, N, visited);
        }
    }
    return count;
}
