#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

/* Compute the discrete Fourier transform of `x`. Store the result in `output`.
   Exact semantics preserved. */
inline std::complex<double> eval_w(int k, int n, int N)
{
    const double ang = 2.0 * M_PI * k * n / N;
    return std::complex<double>(std::cos(ang), -std::sin(ang));
}

void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output)
{
    const int N = static_cast<int>(x.size());
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Pre‑compute the rotation factors for each k
    std::vector<std::complex<double>> w_k(N);
    for (int k = 0; k < N; ++k)
        w_k[k] = std::complex<double>(std::cos(-2.0 * M_PI * k / N),
                                       std::sin(-2.0 * M_PI * k / N)); // exp(-2πi k/N)

    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        const std::complex<double> w = w_k[k];
        std::complex<double> cur(1.0, 0.0);
        std::complex<double> sum(0.0, 0.0);

        for (int n = 0; n < N; ++n) {
            sum += x[n] * cur;
            cur *= w;          // rotational recurrence, no trig per iteration
        }
        output[k] = sum;
    }
}
