struct Point {
   double x, y;
};

/* Count the number of cartesian points in each quadrant.
   The vector `points` contains a list of `Point` objects.
   Store the counts in `bins`.
   Example:
     input:  [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9},
              {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
     output: [3, 1, 0, 2]
*/
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4> &bins) {
   // Initialise result bins
   bins[0] = bins[1] = bins[2] = bins[3] = 0;

   // Thread–local bins to avoid atomic operations
   const size_t nthreads = omp_get_max_threads();
   std::vector<std::array<size_t,4>> local_bins(nthreads);
   for (auto &b : local_bins)
       b[0] = b[1] = b[2] = b[3] = 0;

   #pragma omp parallel
   {
       const int tid = omp_get_thread_num();
       auto &l = local_bins[tid];

       #pragma omp for schedule(static)
       for (size_t i = 0; i < points.size(); ++i) {
           const auto &p = points[i];
           if (p.x >= 0) {
               if (p.y >= 0) ++l[0];
               else           ++l[3];
           } else {
               if (p.y >= 0) ++l[1];
               else           ++l[2];
           }
       }
   }

   // Reduce local bins into the final result
