/* ---- Union‑Find with path compression ---- */
struct UF {
    std::vector<int> parent, sz;
    UF(int n) : parent(n), sz(n, 1) {
        for (int i = 0; i < n; ++i) parent[i] = i;
    }
    int find(int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    void unite(int a, int b) {
        int ra = find(a);
        int rb = find(b);
        if (ra == rb) return;
        /* make the larger set the new root */
        if (sz[ra] < sz[rb]) std::swap(ra, rb);
        parent[rb] = ra;
        sz[ra] += sz[rb];
    }
};

/* ---- Largest component size ---- */
int largestComponent(const std::vector<int> &A, size_t N) {
    /* union all edges */
    UF uf((int)N);
    #pragma omp parallel for schedule(dynamic,256)
    for (int i = 0; i < (int)N; ++i) {
        for (int j = i+1; j < (int)N; ++j) {
            if (A[i * N + j] == 1) {
                /* critical section to avoid data races on UF */
                #pragma omp critical
                uf.unite(i, j);
            }
        }
    }

    /* count component sizes */
    std::vector<int> compSize(N, 0);
    int maxSize = 0;
    for (int i = 0; i < (int)N; ++i) {
        int root = uf.find(i);
        int sz = ++compSize[root];
        if (sz > maxSize) maxSize = sz;
    }
    return maxSize;
}
