#pragma once
#include <vector>
#include <unordered_map>
#include <utility>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 *  Sparse‑dense matrix multiplication:
 *      Y = A x X
 *  A : M x K sparse matrix in COO format.
 *  X : K x N sparse matrix in COO format.
 *  Y : M x N dense matrix in row‑major.
 *
 *  This implementation builds a hash map from the rows of X to the
 *  column/value pairs that originate in that row.  The outer loop over
 *  the entries of A is then parallelised with OpenMP.  Each thread keeps
 *  its own local Y buffer to avoid atomic updates; the final result is
 *  accumulated at the end.
 */
inline void spmm(const std::vector<COOElement>  &A,
                 const std::vector<COOElement>  &X,
                 std::vector<double>           &Y,
                 size_t                            M,
                 size_t                            K,
                 size_t                            N) {
    Y.assign(M * N, 0.0);

    /* Build hash table: for every row r in X keep the columns and
       values of the non‑zero elements in that row.
       key : row index
       value : vector of (col, value) pairs
    */
    std::unordered_map<size_t, std::vector<std::pair<size_t,double>>> rows;
    rows.reserve(X.size() * 2);
    for (const auto &e : X) {
        rows[e.row].emplace_back(e.column, e.value);
    }

    const size_t num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> localY(num_threads, std::vector<double>(M * N, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto &buf = localY[tid];

        #pragma omp for schedule(static)
        for (size_t i = 0; i < A.size(); ++i) {
            const auto &a = A[i];
            auto it = rows.find(a.column);
            if (it == rows.end()) continue;          // no matching row in X
            for (const auto &p : it->second) {
                size_t idx = a.row * N + p.first;
                buf[idx] += a.value * p.second;
            }
        }
    }

    /* Reduce per‑thread buffers into the final result */
    for (size_t t = 0; t < num_threads; ++t) {
        const auto &buf = localY[t];
        for (size_t i = 0; i < M * N; ++i) {
            Y[i] += buf[i];
        }
    }
}
