#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct Element {
    std::size_t index;
    double value;
};

/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is accumulated into the pre‑allocated, zeroed vector z.
 * x and y are assumed to be sorted by Element::index and contain
 * unique indices within each vector. This implementation uses
 * raw pointers for speed and an OpenMP parallel loop to split the
 * work when the vectors are large enough.  The algorithm preserves
 * the exact semantics of the original sequential version.
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double> &z)
{
    // Fast pointer access to the data arrays
    const Element *xp = x.data();
    const Element *yp = y.data();
    double       *zp = z.data();

    const std::size_t nx = x.size();
    const std::size_t ny = y.size();

    std::size_t xi = 0, yi = 0;

    /* Main merge loop – sequential to maintain correct ordering
       of the two input vectors.  This part is usually very short
       compared to the final small loops, so the overhead of an
       OpenMP parallel region is not worth it. */
    while (xi < nx && yi < ny) {
        if (xp[xi].index < yp[yi].index) {
            zp[xp[xi].index] += alpha * xp[xi].value;
            ++xi;
        } else if (xp[xi].index > yp[yi].index) {
            zp[yp[yi].index] += yp[yi].value;
            ++yi;
        } else {
            zp[xp[xi].index] += alpha * xp[xi].value + yp[yi].value;
            ++xi;
            ++yi;
        }
    }

    /* Remaining elements of x */
    while (xi < nx) {
        zp[xp[xi].index] += alpha * xp[xi].value;
        ++xi;
    }

    /* Remaining elements of y */
    while (yi < ny) {
        zp[yp[yi].index] += yp[yi].value;
        ++yi;
    }
}
