#pragma once
#include <cstdint>
#include <vector>
#include <algorithm>
#include <numeric>
#include <omp.h>

/*
 * Compute the inclusive prefix sum of the vector `x` into `output`.
 * The implementation is thread‑safe and maximises performance on a modern
 * x86‑64 machine with up to 8 hardware threads using OpenMP.
 */
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output)
{
    const std::size_t n = x.size();
    if (output.size() != n) output.resize(n);

    /* 1. Each thread performs a local inclusive prefix on its subrange
     *    and records the total sum of its subrange in `blockSums`. */
    const int numThreads = omp_get_max_threads();
    std::vector<int64_t> blockSums(numThreads, 0);

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const int rank = omp_get_num_threads();
        // Compute subrange for this thread
        std::size_t stride = (n + rank - 1) / rank;          // ceil division
        std::size_t start  = tid * stride;
        std::size_t end    = std::min(start + stride, n);

        if (start >= end) return;                           // empty chunk

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        blockSums[tid] = sum;
    }

    /* 2. Compute the prefix of the block sums serially. */
    std::vector<int64_t> blockPrefix(numThreads, 0);
    std::partial_sum(blockSums.begin(), blockSums.end(), blockPrefix.begin());

    /* 3. Add the offset from previous blocks to each element. */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const int rank = omp_get_num_threads();
        std::size_t stride = (n + rank - 1) / rank;
        std::size_t start  = tid * stride;
        std::size_t end    = std::min(start + stride, n);

        if (start >= end) return;
        const int64_t offset = (tid > 0) ? blockPrefix[tid - 1] : 0;

        for (std::size_t i = start; i < end; ++i)
            output[i] += offset;
    }
}
