/* Compute the area of a triangle from its vertices.
   No intermediate allocation or branching. */
static inline double triArea(const Point& a, const Point& b, const Point& c)
{
    const double cross = a.x * (b.y - c.y) +
                         b.x * (c.y - a.y) +
                         c.x * (a.y - b.y);
    return 0.5 * std::fabs(cross);
}

/*
 * Return the area of the smallest triangle that can be formed by any 3 points.
 * Example:
 *   input: [{0, 10}, {5, 5}, {1,0}, {-1, 1}, {-10, 0}]
 *   output: 5.5
 */
double smallestArea(const std::vector<Point>& points)
{
    const size_t n = points.size();
    if (n < 3)
        return 0.0;

    double minArea = std::numeric_limits<double>::max();

    /* Parallelize the triple loop with a single 3‑way collapse.
       The reduction clause guarantees that the minimum is computed correctly
       even when several threads are updating it concurrently. */
    #pragma omp parallel for collapse(3) reduction(min:minArea) schedule(static)
    for (size_t i = 0; i < n - 2; ++i)
        for (size_t j = i + 1; j < n - 1; ++j)
            for (size_t k = j + 1; k < n; ++k)
            {
                const double area = triArea(points[i], points[j], points[k]);
                if (area < minArea)
                    minArea = area;
            }

    return minArea;
}
