```cpp
#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
   size_t row;
   size_t column;
   double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:
   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
   /* --- Build a dense matrix in a flat array --------------- */
   std::vector<double> mat(N * N, 0.0);
   for (auto const& e : A)
       mat[e.row * N + e.column] = e.value;

   /* --- Make copies that will be modified ----------------- */
   std::vector<double> rhs = b;
   x.assign(N, 0.0);

   /* --- Gaussian elimination with partial pivoting --------- */
#pragma omp parallel for schedule(static)
   for (size_t i = 0; i < N; ++i) {
       /* find pivot row */
       double maxEl = std::abs(mat[i * N + i]);
       size_t maxRow = i;
       for (size_t k = i + 1; k < N; ++k) {
           double val = std::abs(mat[k * N + i]);
           if (val > maxEl) {
               maxEl = val;
               maxRow = k;
           }
       }

       /* swap rows i and maxRow */
       if (maxRow != i) {
           for (size_t k = i; k < N; ++k) {
               std::swap(mat[i * N + k], mat[maxRow * N + k]);
           }
           std::swap(rhs[i], rhs[maxRow]);
       }

       double pivot = mat[i * N + i];
       /* eliminate rows below pivot */
       for (size_t k = i + 1; k < N; ++k) {
           double factor = -mat[k * N + i] / pivot;
           mat[k * N + i] = 0.0;               // explicitly set to zero
           for (size_t j = i + 1; j < N; ++j) {
               mat[k * N + j] += factor * mat[i * N + j];
           }
           rhs[k] += factor * rhs[i];
       }
   }

   /* --- Back substitution --------------------------------- */
   for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
       double sum = rhs[i];
       for (int k = static_cast<int>(i) + 1; k < static_cast<int>(N); ++k)
           sum -= mat[i * N + k] * x[k];
       x[i] = sum / mat[i * N + i];
   }
}
