#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/* In‑place Cooley‑Tukey radix‑2 FFT
   The algorithm is identical to the original but written in a more
   cache‑friendly style, with pre‑computed twiddle factors and
   explicit bit‑reversal.  All calculations are performed in double
   precision, and the result is written into the provided real and
   imaginary vectors, preserving the exact interface. */

void fft(std::vector<std::complex<double>> const& x,
         std::vector<double>& r,
         std::vector<double>& i) noexcept
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // 1. Pre‑compute bit reversal indices
    std::size_t m = std::size_t(std::ceil(std::log2(N)));
    std::vector<std::size_t> rev(N);
    for (std::size_t j = 0; j < N; ++j) {
        std::size_t x = j, y = 0;
        for (std::size_t k = 0; k < m; ++k) {
            y = (y << 1) | (x & 1);
            x >>= 1;
        }
        rev[j] = y;
    }

    // 2. Copy input to a temporary array and apply bit reversal
    std::vector<std::complex<double>> X(N);
    for (std::size_t j = 0; j < N; ++j)
        X[rev[j]] = x[j];

    // 3. Pre‑compute twiddle factors for all stages
    std::vector<std::vector<std::complex<double>>> twiddle(m);
    for (std::size_t s = 0; s < m; ++s) {
        const std::size_t len = 1U << s;
        twiddle[s].resize(len);
        const double angle = -2.0 * M_PI / (len << 1);
        const std::complex<double> exp_factor(std::cos(angle), std::sin(angle));
        twiddle[s][0] = {1.0, 0.0};
        for (std::size_t k = 1; k < len; ++k)
            twiddle[s][k] = twiddle[s][k - 1] * exp_factor;
    }

    // 4. Main FFT butterfly loops
#pragma omp parallel for schedule(static)
    for (std::size_t stage = 0; stage < m; ++stage) {
        const std::size_t len = 1U << (stage + 1);
        const std::size_t half = len >> 1;
        for (std::size_t arm = 0; arm < half; ++arm) {
            const auto& W = twiddle[stage][arm];
            for (std::size_t i = arm; i < N; i += len) {
                const std::size_t j = i + half;
                const std::complex<double> t = X[j] * W;
                X[j] = X[i] - t;
                X[i] += t;
            }
        }
    }

    // 5. Copy results into output vectors
    r.resize(N);
    i.resize(N);
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = X[j].real();
        i[j] = X[j].imag();
    }
}
