#pragma once
#include <vector>
#include <cstddef>

struct COOElement {
    std::size_t row, column;
    double value;
};

/*
 *  Factorize the sparse matrix A into A = L * U where L is a lower
 *  triangular matrix and U is an upper triangular matrix.
 *
 *  A is an NxN matrix stored in COO format.  L and U are back‑to‑back
 *  NxN row‑major arrays that are resized by this function.
 *
 *  Example:
 *      input:  A = [{0,0,4}, {0,1,3}, {1,0,6}, {1,1,3}]
 *      output: L = [{0,0,1}, {1,0,1.5}, {1,1,1}]
 *              U = [{0,0,4}, {0,1,3}, {1,1,-1.5}]
 */
inline void luFactorize(std::vector<COOElement> const& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        std::size_t N)
{
    /* ---------- initialise dense matrix and output arrays ---------- */
    std::vector<double> dense(N * N, 0.0);
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* fill dense matrix */
    for (auto const &e : A)
        dense[e.row * N + e.column] = e.value;

    /* --------------------- LU factorisation --------------------- */
    /* Each row only depends on already computed rows – safe to parallelise */
#pragma omp parallel for schedule(guided)
    for (std::size_t i = 0; i < N; ++i)
    {
        /* ----- compute U[i][j] for j >= i ----- */
        for (std::size_t j = i; j < N; ++j)
        {
            double val = dense[i * N + j];
            for (std::size_t k = 0; k < i; ++k)
                val -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = val;
        }

        /* ----- compute L[i][j] for j < i ----- */
        for (std::size_t j = 0; j < i; ++j)
        {
            double val = dense[i * N + j];
            for (std::size_t k = 0; k < j; ++k)
                val -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = val / U[j * N + j];
        }

        /* diagonal of L is 1 */
        L[i * N + i] = 1.0;
    }
}
