/* Find the k‑th smallest element of the vector x.
   Behavior is identical to sorting the vector and selecting the (k‑1)th
   element, but this implementation is linear on average. */
int findKthSmallest(std::vector<int> const& x, int k) {
    // Copy the input to preserve original data
    std::vector<int> x_copy = x;

    // Place the k‑th smallest element in position k-1
    std::nth_element(x_copy.begin(), x_copy.begin() + (k - 1), x_copy.end());

    // The element that now occupies the k‑th position is the answer
    return x_copy[k - 1];
}
