inline void sortIgnoreZero(std::vector<int> &x)
{
    // Reserve space to avoid reallocations
    std::vector<int> nonZero;
    nonZero.reserve(x.size());

    // First pass: collect all non‑zero elements
    for (const int v : x)
        if (v != 0)
            nonZero.push_back(v);

    // Sort the collected elements
    std::sort(nonZero.begin(), nonZero.end());

    // Second pass: write back the sorted values, keeping zeros in place
    std::size_t idx = 0;
    for (std::size_t i = 0, n = x.size(); i < n; ++i) {
        if (x[i] != 0)
            x[i] = nonZero[idx++];
    }
}
