#pragma once
#include <vector>
#include <omp.h>

/*
 * Compute each cell of the output grid: set to 1 iff the cell has exactly
 * one 1‑valued orthogonal neighbour in the input grid.  The input and
 * output grids are N×N perfect square matrices stored row‑major in
 * std::vector<int>.
 *
 * The implementation is fully data‑parallel and performs all bounds
 * checks once per cell.  The outermost loop is parallelised with OpenMP
 * and the code uses pointer arithmetic for maximal cache efficiency.
 */
inline void cellsXOR(const std::vector<int> &input,
                     std::vector<int> &output,
                     size_t N) {
    const int *in  = input.data();
    int       *out = output.data();
    const size_t stride = N;            // row length

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t base = i * stride;       // index of first element in this row
        const int *rowAbove  = (i > 0)   ? in + (i - 1) * stride : nullptr;
        const int *rowBelow  = (i < N - 1) ? in + (i + 1) * stride : nullptr;

        for (size_t j = 0; j < N; ++j) {
            int count = 0;

            // up
            if (rowAbove && rowAbove[j] == 1) ++count;
            // down
            if (rowBelow && rowBelow[j] == 1) ++count;
            // left
            if (j > 0 && in[base + j - 1] == 1) ++count;
            // right
            if (j < N - 1 && in[base + j + 1] == 1) ++count;

            out[base + j] = (count == 1) ? 1 : 0;
        }
    }
}
