#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

static constexpr int edgeKernel[9] = {   // flattened for cache locality
    -1, -1, -1,
    -1,  8, -1,
    -1, -1, -1
};

/* Convolve the 3×3 edge kernel with a square grayscale image.
   The implementation uses OpenMP parallelisation, a temporary
   padded buffer to eliminate branchy boundary checks, and
   avoids virtual function calls for performance. */
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int> &imageOut,
                           size_t N)
{
    const size_t padded = N + 2;            // one pixel border on each side
    std::vector<int> paddedIn(padded * padded, 0);   // zero‑filled out‑of‑bounds

    /* Copy the original image into the centre of the padded buffer */
    for (size_t i = 0; i < N; ++i)
        std::copy(imageIn.begin() + i * N,
                  imageIn.begin() + (i + 1) * N,
                  paddedIn.begin() + (i + 1) * padded + 1);

    /* Parallel convolution */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t row = (i + 1) * padded + 1;  // starting index of the current row in paddedIn
        size_t dst = i * N;                 // starting index of the current row in imageOut
        for (size_t j = 0; j < N; ++j, ++dst, ++row) {
            int sum =   paddedIn[row - padded - 1] * edgeKernel[0]  // top‑left
                      + paddedIn[row - padded  ] * edgeKernel[1]  // top‑center
                      + paddedIn[row - padded + 1] * edgeKernel[2]  // top‑right
                      + paddedIn[row - 1        ] * edgeKernel[3]  // middle‑left
                      + paddedIn[row        ] * edgeKernel[4]      // centre
                      + paddedIn[row + 1        ] * edgeKernel[5]  // middle‑right
                      + paddedIn[row + padded - 1] * edgeKernel[6] // bottom‑left
                      + paddedIn[row + padded   ] * edgeKernel[7] // bottom‑center
                      + paddedIn[row + padded + 1] * edgeKernel[8]; // bottom‑right

            /* Clamp to 0‑255 */
            imageOut[dst] = static_cast<int>(std::clamp(sum, 0, 255));
        }
    }
}
