```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cmath>

struct Point {
    double x, y;
};

namespace detail {
    inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    }

    inline double dist(const Point& a, const Point& b) noexcept {
        double dx = a.x - b.x;
        double dy = a.y - b.y;
        return std::sqrt(dx * dx + dy * dy);
    }
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points. */
inline double convexHullPerimeter(const std::vector<Point>& points) noexcept {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    // copy and sort
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // build hull
    std::vector<Point> hull(2 * n);
    size_t k = 0;

    for (size_t i = 0; i < n; ++i) {
        while (k >= 2 &&
               detail::cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        hull[k++] = sorted[i];
    }

    for (size_t i = n - 1, t = k + 1; i > 0; --i) {
        while (k >= t &&
               detail::cross(hull[k - 2], hull[k - 1], sorted[i - 1]) <= 0.0)
            --k;
        hull[k++] = sorted[i - 1];
    }

    hull.resize(k - 1);

    // perimeter
    double perim = 0.0;
    for (size_t i = 0; i + 1 < hull.size(); ++i)
        perim += detail::dist(hull[i], hull[i + 1]);
    perim += detail::dist(hull.front(), hull.back());

    return perim;
}
```
This implementation replaces the repeated `pow`/`sqrt` calls with a single `sqrt` in the `dist` function, uses `inline` helpers for zero‑allocation, and avoids creating unnecessary temporaries, resulting in a more efficient convex hull perimeter calculation.

