/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
size_t findClosestToPi(std::vector<double> const& x) {
    if (x.empty()) return 0;                                   // defensive: empty list returns 0
    const double pi = M_PI;
    size_t best_idx = 0;
    double best_val = std::abs(x[0] - pi);

    // parallel reduction over value and index
    #pragma omp parallel for reduction(min:min_val)
    for (size_t i = 0; i < x.size(); ++i) {
        double d = std::abs(x[i] - pi);
        #pragma omp critical
        {
            if (d < best_val) {
                best_val = d;
                best_idx = i;
            }
        }
    }
    return best_idx;
}
