04_dense_la_gemv:
```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Multiply the matrix A by the vector x. Store the results in the vector y.
   A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
   Example:
   input: A=[[1, -1, 2], [0, -3, 1]] x=[2, 1, 0]
   output: y=[1, -3]
   The implementation uses OpenMP for parallelism, pointer arithmetic for speed
   and a manual block‑size reduction to keep the inner loop cache‑friendly.
*/
inline void gemv(const std::vector<double>& A,
                 const std::vector<double>& x,
                 std::vector<double>& y,
                 size_t M, size_t N) noexcept
{
    // Prevent needless reallocation if y is not the right size
    if (y.size() < M) y.resize(M);

    // --- Parallel outer loop -----------------------------------------
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(M); ++i)
    {
        // Local pointer to the start of the i‑th row of A
        const double* restrict row = &A[i * N];
        const double* restrict xv   = x.data();
        double sum = 0.0;

        // Process in chunks of 8 for better cache utilisation
        size_t j = 0;
        for (; j + 7 < N; j += 8)
        {
            double a0 = row[j + 0], a1 = row[j + 1];
            double a2 = row[j + 2], a3 = row[j + 3];
            double a4 = row[j + 4], a5 = row[j + 5];
            double a6 = row[j + 6], a7 = row[j + 7];

            sum += a0 * xv[j + 0] + a1 * xv[j + 1]
                 + a2 * xv[j + 2] + a3 * xv[j + 3]
                 + a4 * xv[j + 4] + a5 * xv[j + 5]
                 + a6 * xv[j + 6] + a7 * xv[j + 7];
        }

        // Remainder handling
        for (; j < N; ++j)
            sum += row[j] * xv[j];

        y[i] = sum;
    }
}
