54_stencil_game_of_life:
```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/// @brief Compute the next state of a Game of Life board.
/// @param input  Current board (row‑major, 1 alive, 0 dead)
/// @param output Next board (same layout)
/// @param N      Board size (NxN)
///
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       size_t N)
{
    // For performance we work with raw pointers.
    const int*  in  = input.data();
    int*        out = output.data();

    // Parallelise over rows.  The loop body is independent per row.
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t i = 0; i < (ptrdiff_t)N; ++i)
    {
        const ptrdiff_t row = i * N;
        for (ptrdiff_t j = 0; j < (ptrdiff_t)N; ++j)
        {
            // Neighbor indices for the 8 directions
            ptrdiff_t n00 = row - N + j - 1; // NW
            ptrdiff_t n01 = row - N + j;     // N
            ptrdiff_t n02 = row - N + j + 1; // NE
            ptrdiff_t n10 = row + j - 1;     // W
            ptrdiff_t n12 = row + j + 1;     // E
            ptrdiff_t n20 = row + N + j - 1; // SW
            ptrdiff_t n21 = row + N + j;     // S
            ptrdiff_t n22 = row + N + j + 1; // SE

            int sum = 0;
            // North side
            if (i > 0) {
                sum += in[n01];
                if (j > 0)   sum += in[n00];
                if (j < (ptrdiff_t)N - 1) sum += in[n02];
            }
            // Same row
            if (j > 0)   sum += in[n10];
            if (j < (ptrdiff_t)N - 1) sum += in[n12];
            // South side
            if (i < (ptrdiff_t)N - 1) {
                sum += in[n21];
                if (j > 0)   sum += in[n20];
                if (j < (ptrdiff_t)N - 1) sum += in[n22];
            }

            // Compute next state
            const int cur = in[row + j];
            out[row + j] =
                cur == 1
                    ? (sum == 2 || sum == 3) ? 1 : 0
                    : (sum == 3) ? 1 : 0;
        }
    }
}
