02_dense_la_gemm:
```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix.
   Matrices are stored in row‑major order.
   The implementation is cache‑friendly and parallelised with OpenMP.
   The execution remains bitwise identical to the naive implementation. */
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Cache friendly blocking sizes (tuned for a typical L2/L3 cache)
    constexpr size_t BLOCK_M = 64;
    constexpr size_t BLOCK_K = 64;
    constexpr size_t BLOCK_N = 64;

    // Zero the result matrix first (the naive routine assumes C is
    // already initialised to zero; we keep the same contract).
    std::fill(C.begin(), C.end(), 0.0);

    // Parallelise over the outermost block of rows (i loop)
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK_M) {
        size_t i_max = std::min(ii + BLOCK_M, M);
        for (size_t kk = 0; kk < K; kk += BLOCK_K) {
            size_t k_max = std::min(kk + BLOCK_K, K);
            for (size_t jj = 0; jj < N; jj += BLOCK_N) {
                size_t j_max = std::min(jj + BLOCK_N, N);

                // Compute the block [ii:i_max) x [jj:j_max)
                for (size_t i = ii; i < i_max; ++i) {
                    double* c_row = &C[i * N + jj];
                    const double* a_row = &A[i * K + kk];
                    for (size_t k = kk; k < k_max; ++k) {
                        const double a_val = a_row[k];
                        const double* b_row = &B[k * N + jj];
                        for (size_t j = jj; j < j_max; ++j) {
                            c_row[j - jj] += a_val * b_row[j - jj];
                        }
                    }
                }
            }
        }
    }
}
