```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <omp.h>

#ifndef M_PI
#  define M_PI 3.1415926535897932384626433832795028841971
#endif

// ---------------------------------------------------------------------------
// Iterative Cooley–Tukey radix‑2 FFT (Decimation‑In‑Frequency)
// ---------------------------------------------------------------------------
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // Pre‑compute bit‑reversal permutation table
    const std::size_t m = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t r = 0;
        for (std::size_t j = 0; j < m; ++j)
            r = (r << 1) | ((i >> j) & 1u);
        rev[i] = r;
    }
    for (std::size_t i = 0; i < N; ++i)
        if (rev[i] > i)
            std::swap(x[i], x[rev[i]]);

    // Main FFT loop
    const double pi = M_PI;
    for (std::size_t s = 1; s <= m; ++s)
    {
        const std::size_t stride = 1ULL << s;
        const std::size_t half   = stride >> 1;
        const double  theta     = -2.0 * pi / static_cast<double>(stride);
        const std::complex<double> w_step(std::cos(theta), std::sin(theta));

        // Parallel over the outer butterfly groups
#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += stride)
        {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t n = 0; n < half; ++n)
            {
                std::complex<double> t = w * x[k + n + half];
                std::complex<double> u = x[k + n];
                x[k + n]       = u + t;
                x[k + n + half] = u - t;
                w *= w_step;
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Inverse FFT: conjugate → FFT → conjugate → scale
// ---------------------------------------------------------------------------
inline void ifft(std::vector<std::complex<double>>& x)
{
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });
    fft_helper(x);
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });
    const double invN = 1.0 / static_cast<double>(x.size());
    for (auto& v : x) v *= invN;
}
