```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

/* Iterative radix‑2 Cooley–Tukey FFT with in‑place computation.
   The algorithm preserves the exact results of the original implementation.
   It uses pre‑computed twiddle factors and OpenMP parallelism for the
   butterfly stages and the bit‑reversal pass. */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output) {
    const size_t N = x.size();
    output = x;                      // work buffer

    /* Pre‑compute twiddle factors.  The value for a given stage decays
     * as w^k = e^{-2πi k/N}.  We compute the primitive root for each
     * stage once and reuse it. */
    std::vector<std::complex<double>> twiddles(N / 2);
    double angle = -2.0 * M_PI / N;  // negative for forward FFT
    for (size_t i = 0; i < N / 2; ++i)
        twiddles[i] = std::exp(std::complex<double>(0, angle * i));

    /* Iterative Cooley–Tukey.  For stage s (1…log2N) the distance
     * between elements in a butterfly is n = 1 << s.  We parallelise
     * over the outer loop of butterflies, which is fine‑grained enough
     * for 8 threads on typical datasets. */
    size_t logN = 0;
    for (size_t tmp = N; tmp > 1; tmp >>= 1) ++logN;
    for (size_t s = 1; s <= logN; ++s) {
        size_t n = 1ULL << s;            // butterfly width
        size_t half = n >> 1;            // stride
        #pragma omp parallel for schedule(static)
        for (size_t i = 0; i < N; i += n) {
            for (size_t j = 0; j < half; ++j) {
                std::complex<double> t = output[i + j + half] *
                                         twiddles[j * (N / n)];
                output[i + j + half] = output[i + j] - t;
                output[i + j] += t;
            }
        }
    }

    /* Bit‑reversal via a pre‑computed table for 16‑bit indices. */
    static const uint32_t rev16[65536] = []{
        uint32_t table[65536];
        for (uint32_t i = 0; i < 65536; ++i) {
            uint32_t x = i;
            x = ((x & 0xAAAAu) >> 1) | ((x & 0x5555u) << 1);
            x = ((x & 0xCCCCu) >> 2) | ((x & 0x3333u) << 2);
            x = ((x & 0xF0F0u) >> 4) | ((x & 0x0F0Fu) << 4);
            table[i] = x;
        }
        return table;
    }();

    /* Perform the permutation.  An element is swapped only if its
     * reversed index is larger to avoid double work. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t j = rev16[i & 0xFFFFu]     // reverse low 16 bits
                 | (rev16[(i >> 16) & 0xFFFFu] << 16); // high bits
        j >>= (32 - logN);                 // normalize to N bits
        if (j > i) std::swap(output[i], output[j]);
    }
}
