/* Sort a vector of complex numbers by their magnitude (|z| = sqrt(Re^2+Im^2))
   in ascending order.  The ``std::abs`` function is called exactly once per
   element, and the actual sorting work is performed in parallel with up to
   eight threads (the default OpenMP thread count under GCC).  The function
   preserves the original interface and semantics. */
inline void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    const std::size_t n = x.size();
    if (n <= 1) return;

    // --------------------------------------------------------------------
    // 1. Compute magnitudes once and store them in a separate buffer.
    std::vector<double> mag(n);
    for (std::size_t i = 0; i < n; ++i) {
        mag[i] = std::abs(x[i]);           // one sqrt per element
    }

    // --------------------------------------------------------------------
    // 2. Sort an index vector according to the magnitudes.
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    // GNU parallel std::sort provides a true multi‑threaded sort.
    __gnu_parallel::sort(
        idx.begin(),
        idx.end(),
        [&](std::size_t a, std::size_t b) { return mag[a] < mag[b]; }
    );

    // --------------------------------------------------------------------
    // 3. Reconstruct the sorted vector in place.
    //    We use a temporary vector to avoid many individual swaps.
    std::vector<std::complex<double>> sorted;
    sorted.reserve(n);
    for (std::size_t i = 0; i < n; ++i) {
        sorted.push_back(std::move(x[idx[i]]));
    }
    x.swap(sorted);
}
