inline bool xorContains(std::vector<int> const& x, std::vector<int> const& y, int val) noexcept
{
    // Scan the first vector
    bool foundInX = false;
    const int* px = x.data();
    const std::size_t nx = x.size();
    for (std::size_t i = 0; i < nx; ++i)
    {
        if (px[i] == val)
        {
            foundInX = true;
            break;
        }
    }

    // Scan the second vector
    bool foundInY = false;
    const int* py = y.data();
    const std::size_t ny = y.size();
    for (std::size_t i = 0; i < ny; ++i)
    {
        if (py[i] == val)
        {
            foundInY = true;
            break;
        }
    }

    // Exclusive-or the two results
    return foundInX ^ foundInY;
}
