#pragma once
#include <vector>
#include <algorithm>

struct Point {
    double x, y;
};

inline void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    const std::size_t n = points.size();
    if (n < 3) {
        hull = points;  // copy small input directly
        return;
    }

    // Work on a copy that can be sorted
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // Allocate enough space for the upper + lower hull
    std::vector<Point> temp(2 * n);
    std::size_t k = 0;

    // Inline cross-product helper (returns signed area)
    auto cross = [](const Point& a, const Point& b, const Point& c) -> double {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    // Lower hull (left to right)
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(temp[k - 2], temp[k - 1], pts[i]) <= 0) {
            --k;   // pop last point
        }
        temp[k++] = pts[i];
    }

    // Upper hull (right to left)
    const std::size_t t = k + 1;
    for (std::size_t i = n - 1; i > 0; --i) {
        while (k >= t && cross(temp[k - 2], temp[k - 1], pts[i - 1]) <= 0) {
            --k;   // pop last point
        }
        temp[k++] = pts[i - 1];
    }

    // Resize to actual hull size (last point repeats first one)
    temp.resize(k - 1);

    // Move result out to the caller without extra copy
    hull.swap(temp);
}
