#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*  LU factorisation (partial pivoting is not required here).
    The result is written back into A in place.
*/
inline void luFactorize(std::vector<double> &A, size_t N) {
#if defined(_OPENMP)
    for (size_t k = 0; k < N; ++k) {
        const size_t k_off = k * N;
        const double akk = A[k_off + k];

        // Parallelise the elimination of rows i > k
        #pragma omp parallel for schedule(static, 64)
        for (size_t i = k + 1; i < N; ++i) {
            const size_t i_off = i * N;
            const double factor = A[i_off + k] / akk;
            A[i_off + k] = factor;                   // store L entry

            // Update the trailing sub‑matrix row by row
            double *row_i = &A[i_off + k + 1];
            const double *row_k = &A[k_off + k + 1];
            size_t j = k + 1;
            const size_t end = N;

            // SIMD friendly unrolled loop (4× unroll)
            for (; j + 3 < end; j += 4) {
                row_i[0] -= factor * row_k[0];
                row_i[1] -= factor * row_k[1];
                row_i[2] -= factor * row_k[2];
                row_i[3] -= factor * row_k[3];
                row_i += 4;
                row_k += 4;
            }
            // Handle remaining tail elements
            for (; j < end; ++j) {
                row_i[0] -= factor * row_k[0];
                ++row_i;
                ++row_k;
            }
        }
    }
#else
    // Fallback sequential implementation
    for (size_t k = 0; k < N; ++k) {
        const size_t k_off = k * N;
        const double akk = A[k_off + k];
        for (size_t i = k + 1; i < N; ++i) {
            const size_t i_off = i * N;
            const double factor = A[i_off + k] / akk;
            A[i_off + k] = factor;
            for (size_t j = k + 1; j < N; ++j) {
                A[i_off + j] -= factor * A[k_off + j];
            }
        }
    }
#endif
}
