#pragma once
#include <algorithm>
#include <numeric>
#include <vector>

/*
 * For each value in the vector `x` compute its index in the sorted vector
 * and store the results in `ranks_`. The relative order of equal elements
 * follows the order in the original array (stable behaviour).
 * Example:
 *   input : [3.1, 2.8, 9.1, 0.4, 3.14]
 *   output: [2, 1, 4, 0, 3]
 *   input : [100, 7.6, 16.1, 18, 7.6]
 *   output: [4, 0, 1, 2, 3]
 */
void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    const size_t n = x.size();
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);

    // Stable-like ordering: if values equal, keep original index order
    std::sort(indices.begin(), indices.end(),
              [&x](size_t i1, size_t i2) {
                  if (x[i1] < x[i2]) return true;
                  if (x[i2] < x[i1]) return false;
                  return i1 < i2;   // tie‑break by original index
              });

    // build inverse mapping
    for (size_t i = 0; i < n; ++i) {
        ranks_[indices[i]] = i;
    }
}
