#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstddef>
#include <omp.h>

void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // ----- bit‑reversal permutation -----
    const unsigned int m = static_cast<unsigned int>(std::ceil(std::log2(static_cast<double>(N))));
    for (std::size_t i = 1, j = 0; i < N; ++i)
    {
        j = (j << 1) | (i >> (m - 1));
        if (i < j)
            std::swap(x[i], x[j]);
    }

    // ----- iterative radix‑2 Cooley‑Tukey FFT -----
    for (std::size_t len = 2, step = 1; len <= N; len <<= 1, step <<= 1)
    {
        const double ang = -2.0 * M_PI / static_cast<double>(len);
        const double wlen_c = std::cos(ang);
        const double wlen_s = std::sin(ang);

#pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len)
        {
            double u_c = 1.0, u_s = 0.0;
            for (std::size_t j = 0; j < step; ++j)
            {
                const std::size_t a = i + j;
                const std::size_t b = a + step;

                const std::complex<double> t = std::complex<double>(u_c, u_s) * x[b];
                x[b] = x[a] - t;
                x[a] += t;

                // multiply u by the twiddle factor wlen
                const double next_c = u_c * wlen_c - u_s * wlen_s;
                const double next_s = u_c * wlen_s + u_s * wlen_c;
                u_c = next_c;
                u_s = next_s;
            }
        }
    }

    // ----- conjugate the spectrum -----
    for (auto& c : x)
        c = std::conj(c);
}
