#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

void solveLinearSystem(std::vector<double> const& A, std::vector<double> const& b,
                       std::vector<double> &x, std::size_t N)
{
    // Work on local copies
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    double* restrict Ap = A_copy.data();
    double* restrict bp = b_copy.data();

    const std::size_t stride = N;          // row length

    /* Gaussian elimination with parallel row updates */
    for (std::size_t i = 0; i + 1 < N; ++i) {
        const double pivot = Ap[i * stride + i];

        // Exact zero pivot -> singular, keep original behaviour (return)
        if (pivot == 0.0) return;

        const double inv_piv = 1.0 / pivot;

        /* Parallel over the rows below the pivot */
#pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            const double factor = Ap[j * stride + i] * inv_piv;

            /* Update the row j from column i to the end */
            double* restrict row_j = Ap + j * stride + i;
            const double* restrict row_i = Ap + i * stride + i;

            std::size_t k = 0;
            // vectorized forward part
            for (; k + 3 < (N - i); k += 4) {
                row_j[k]     -= factor * row_i[k];
                row_j[k + 1] -= factor * row_i[k + 1];
                row_j[k + 2] -= factor * row_i[k + 2];
                row_j[k + 3] -= factor * row_i[k + 3];
            }
            for (; k < (N - i); ++k) {
                row_j[k] -= factor * row_i[k];
            }

            /* Update the RHS */
            bp[j] -= factor * bp[i];
        }
    }

    /* Back substitution */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double* restrict row = Ap + i * stride + i + 1;
        for (std::size_t j = i + 1; j < N; ++j) {
            sum += row[j - i - 1] * x[j];
        }
        x[i] = (bp[i] - sum) / Ap[i * stride + i];
    }
}
