#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Compute one iteration of a 5‑point 2‑D Jacobi stencil.
 * The loop is fully parallelised with OpenMP, and inner
 * boundaries are handled in separate small kernels to avoid
 * conditional branches inside the hot inner loop.
 *
 * Remarks:
 *   - Indexing uses pointer arithmetic for speed.
 *   - Constant 1/5 is pre‑computed as 0.2 to avoid division.
 */
inline static constexpr double INV5 = 0.2;

void jacobi2D(const std::vector<double>& input,
              std::vector<double>& output,
              size_t N)
{
    const double *in  = input.data();
    double       *out = output.data();

    // Outer loop is parallelised; schedule(static) gives good load balance
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t base = i * N;
        const size_t up   = (i > 0)       ? (i-1) * N : static_cast<size_t>(-1);
        const size_t down = (i + 1 < N)   ? (i+1) * N : static_cast<size_t>(-1);

        /* ----- Core part – inner j from 1 to N-2 ----- */
        for (size_t j = 1; j + 1 < N; ++j) {
            const size_t idx = base + j;
            double sum = in[idx];
            sum += in[up   + j];
            sum += in[down + j];
            sum += in[base + j - 1];
            sum += in[base + j + 1];
            out[idx] = sum * INV5;
        }

        /* ----- First column (j = 0) ----- */
        if (N > 0) {
            const size_t idx = base;
            double sum = in[idx];
            sum += in[up   + 0];
            sum += in[down + 0];
            /* left neighbour is outside --> treat as 0 */
            sum += in[base  + 1];
            out[idx] = sum * INV5;
        }

        /* ----- Last column (j = N-1) ----- */
        if (N > 1) {
            const size_t j = N - 1;
            const size_t idx = base + j;
            double sum = in[idx];
            sum += in[up   + j];
            sum += in[down + j];
            sum += in[base + j - 1];
            /* right neighbour is outside --> treat as 0 */
            out[idx] = sum * INV5;
        }
    }
}
